#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e4+5;
int match[MAXN],st[MAXN],ans,n,t;
bool f[110][110];
vector<int> g[MAXN];
int make(int x,int y)
{
    return (x-1)*n+y;
}
bool solve(int u) 
{
    if(st[u])return false;
    st[u]=1;
    FOI(c,g[u])
    {
		if(!match[c]||solve(match[c]))
		{
			match[c]=u;
			return true;
		}
	}
    return false;
}
signed main(void)
{
    n=read(),t=read();
    FOR(i,1,t)
	{
        int u=read(),v=read();
        f[u][v]=1;   
    }
    FOR(i,1,n)
	{
        FOR(j,1,n)
		{
            if(f[i][j])
			{
				continue;
			}
            if(!f[i+1][j]&&i!=n)
			{
                g[make(i,j)].pb(make(i+1,j));
                g[make(i+1,j)].pb(make(i,j));
            }
            if(!f[i][j+1]&&j!=n)
			{
                g[make(i,j)].pb(make(i,j+1));
	            g[make(i,j+1)].pb(make(i,j));
            }
        }
    }
    FOR(i,1,n*n)
	{
        memset(st,0,sizeof st);
        if(solve(i))++ans;
    }
    write(ans/2);
    return false;
}
